--&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%89%8D%E8%A8%80&#34;&gt;еүҚиЁҖ&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%89%8D%E7%AB%AF&#34;&gt;еүҚз«Ҝ&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%BD%91%E9%A1%B5%E6%9C%8D%E5%8A%A1%E5%99%A8&#34;&gt;зҪ‘йЎөжңҚеҠЎеҷЁ&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#vscode&#34;&gt;VScode&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#idea&#34;&gt;IDEA&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#markdown&#34;&gt;Markdown&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#tomcat&#34;&gt;Tomcat&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;еүҚиЁҖ&#34;&gt;еүҚиЁҖ&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;ејҖдә’иҒ”зҪ‘еүҚз«ҜиҜҫзЁӢдәҶ,еҜ№дәҺе·Ҙе…·зҡ„йҖүз”ЁзЎ®е®һжңүдәӣжқӮд№ұ,дә”иҠұе…«й—Ё&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дёӢйқўз®ҖеҚ•еұ•зӨәдёӨж¬ҫ IDE еҗ§вҖ“&amp;gt; &lt;code&gt;VScode&lt;/code&gt; дёҺ &lt;code&gt;IDEA&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;VScode е…Ёз§° &lt;code&gt;Visual Studio Code&lt;/code&gt;,жҳҜејҖжәҗе…Қиҙ№зҡ„,жңүзј–зЁӢз•ҢжңҖдё°еҜҢзҡ„жҸ’д»¶еёӮеңә&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;IDEA е…Ёз§° &lt;code&gt;IntelliJ IDEA&lt;/code&gt;,жңүејҖжәҗе…Қиҙ№зүҲ,д№ҹжңүж”¶иҙ№зүҲ(еҜ№еӨ§еһӢйЎ№зӣ®жңүжӣҙеҘҪзҡ„ж”ҜжҢҒ),зӣ®еүҚеҸЈиҜ„жңҖеҘҪзҡ„ Java ејҖеҸ‘е·Ҙе…·.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е·Ҙе…·и·ҹйҡҸйңҖжұӮ,йҰ–е…ҲжҲ‘д»¬е…ҲжҺўи®ЁдёӢе…·дҪ“йңҖиҰҒе®ғеҒҡд»Җд№Ҳ?&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;ж–№дҫҝзј–еҶҷеүҚз«Ҝ(HTML,CSS,JavaScript,stylus,less),жЎҶжһ¶(React,Vue,Angular)зӯүзӯү&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;иғҪжһ¶и®ҫиө·зҪ‘йЎөжңҚеҠЎеҷЁ(localhost:xxxx еҸҜд»Ҙи®ҝй—®)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;жңҖеҘҪе…·еӨҮдёҖе®ҡзҡ„жҸ’д»¶жү©еұ•жҖ§.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ж”ҜжҢҒиҜ»еҶҷ&lt;code&gt;.md&lt;/code&gt;ж јејҸзҡ„ markdown ж–Үд»¶.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;еүҚз«Ҝ&#34;&gt;еүҚз«Ҝ&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;йҰ–е…Ҳ,зј–еҶҷж–№йқўжІЎе•ҘеҸҜиҜҙзҡ„,VScode еңЁеүҚз«Ҝ/жЎҶжһ¶ж–№йқўж”ҜжҢҒйғҪжҳҜж•°дёҖж•°дәҢзҡ„,IDEA зҡ„иҜқ,жӢҝжқҘеҶҷеүҚз«Ҝе…¶е®һд№ҹзӣёеҪ“еҮәиүІ.&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;зҪ‘йЎөжңҚеҠЎеҷЁ&#34;&gt;зҪ‘йЎөжңҚеҠЎеҷЁ&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;ж•ҷеӯҰиҖҒеёҲз”Ёзҡ„жҳҜ MyEclipse+tomcat жһ¶и®ҫзҡ„зҪ‘йЎөжңҚеҠЎеҷЁ,жҗӯе»әж—¶йңҖиҰҒжҗһ MyEclipse,&lt;s&gt;з ҙи§Ј&lt;/s&gt;,й…ҚзҪ® Tomcat(иҖҢдё” Tomcat йңҖиҰҒ JDK)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;еҲ«жҸҗеӨҡеӨҙз–јдәҶ!&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;жҲ‘еҶҷиҝҷдёӘж–Үз« е°ұжҳҜдёәдәҶи§ЈеҶіиҝҷдёӘй—®йўҳ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;VScode еҫҲеӨҡдјҳз§Җжү©еұ•ејҖз®ұеҚіз”ЁзҪ‘йЎөжңҚеҠЎеҷЁ!&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;IDEA еҺҹз”ҹж”ҜжҢҒзҪ‘йЎөжңҚеҠЎеҷЁ!&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дёӢйқўд»Ӣз»ҚжҖҺд№Ҳз”Ё:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;еҸҜдҫӣеҸӮиҖғзҡ„жөӢиҜ• html ж–Үд»¶:&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;!DOCTYPE &lt;span class=&#34;keyword&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;lang&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;en&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;meta&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;charset&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;UTF-8&amp;quot;&lt;/span&gt; /&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;Title&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;https://cdn.bootcdn.net/ajax/libs/jquery/3.5.1/jquery.min.js&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;style&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;language-css&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;      &lt;span class=&#34;selector-id&#34;&gt;#divMove&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;width&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;500px&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;height&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;500px&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;border&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;1px&lt;/span&gt; solid &lt;span class=&#34;number&#34;&gt;#ff0000&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;font-size&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;30px&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;text-align&lt;/span&gt;: center;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;      &amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;    &lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;style&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;&amp;lt;!--иҰҒжұӮпјҡиҺ·еҸ–йј ж ҮеҪ“еүҚзҡ„дёҖдёӘеқҗж Ү--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Mouse &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;span&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;mouseMove&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;span&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;divMove&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;еңЁиҝҷйҮҢз§»еҠЁйј ж ҮиҜ•иҜ•&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;language-javascript&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;       * ! еҪ“зҪ‘йЎөе…ғзҙ еҠ иҪҪе®ҢжҜ•д№ӢеҗҺпјҢе“Қеә”дәӢд»¶&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;       * еҺҹеһӢ: $(document).ready(function()&amp;#123;&amp;#125;);&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;       * з®ҖеҢ–еҗҺзҡ„: $(function ()&amp;#123;&amp;#125;);&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;       */&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;      $(&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;        $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#divMove&amp;quot;&lt;/span&gt;).&lt;span class=&#34;title function_&#34;&gt;mousemove&lt;/span&gt;(&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;e&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;          $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#mouseMove&amp;quot;&lt;/span&gt;).&lt;span class=&#34;title function_&#34;&gt;text&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;X: &amp;quot;&lt;/span&gt; + e.&lt;span class=&#34;property&#34;&gt;pageX&lt;/span&gt; + &lt;span class=&#34;string&#34;&gt;&amp;quot;Y: &amp;quot;&lt;/span&gt; + e.&lt;span class=&#34;property&#34;&gt;pageY&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;        &amp;#125;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;      &amp;#125;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-javascript&#34;&gt;    &lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
