&lt;h3 id=&#34;еҸҰдёҖз§ҚзӣёеҶҢеҪўејҸ-иҮӘеҠЁжҺ’еҲ—&#34;&gt;еҸҰдёҖз§ҚзӣёеҶҢеҪўејҸ(иҮӘеҠЁжҺ’еҲ—)&lt;/h3&gt;
&lt;figure class=&#34;highlight scss&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% gallery %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;!&lt;span class=&#34;selector-attr&#34;&gt;[еӣҫзүҮжҸҸиҝ°]&lt;/span&gt;(еӣҫзүҮең°еқҖ)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;!&lt;span class=&#34;selector-attr&#34;&gt;[еӣҫзүҮжҸҸиҝ°]&lt;/span&gt;(еӣҫзүҮең°еқҖ)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;!&lt;span class=&#34;selector-attr&#34;&gt;[еӣҫзүҮжҸҸиҝ°]&lt;/span&gt;(еӣҫзүҮең°еқҖ)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% endgallery %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h2 id=&#34;tag-hide&#34;&gt;tag-hide&lt;/h2&gt;
&lt;h3 id=&#34;inline-дёҖиЎҢеҶ…&#34;&gt;inline(дёҖиЎҢеҶ…)&lt;/h3&gt;
&lt;figure class=&#34;highlight maxima&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;span class=&#34;symbol&#34;&gt;%&lt;/span&gt; hideInline &lt;span class=&#34;built_in&#34;&gt;content&lt;/span&gt;,&lt;span class=&#34;built_in&#34;&gt;display&lt;/span&gt;,bg,&lt;span class=&#34;built_in&#34;&gt;color&lt;/span&gt; &lt;span class=&#34;symbol&#34;&gt;%&lt;/span&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;content&lt;/span&gt;: ж–Үжң¬еҶ…е®№&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;display&lt;/span&gt;: жҢүй’®жҳҫзӨәзҡ„ж–Үеӯ— (еҸҜйҖү)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  bg: жҢүй’®зҡ„иғҢжҷҜйўңиүІ (еҸҜйҖү)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;color&lt;/span&gt;: жҢүй’®ж–Үеӯ—зҡ„йўңиүІ (еҸҜйҖү)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;дҫӢеҰӮ 1:&lt;/p&gt;
&lt;p&gt;&lt;code&gt;жҲ‘жҳҜи°Ғ:&amp;#123;% hideInline Weidows,жҹҘзңӢзӯ”жЎҲ,#FF7242,#fff %&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;жҲ‘жҳҜи°Ғ:&lt;span class=&#34;hide-inline&#34;&gt;&lt;button type=&#34;button&#34; class=&#34;hide-button&#34; style=&#34;background-color: #FF7242;color: #fff&#34;&gt;жҹҘзңӢзӯ”жЎҲ
  &lt;/button&gt;&lt;span class=&#34;hide-content&#34;&gt;Weidows&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;Block-еқ—&#34;&gt;Block(еқ—)&lt;/h3&gt;
&lt;figure class=&#34;highlight django&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;template-tag&#34;&gt;&amp;#123;% &lt;span class=&#34;name&#34;&gt;hideBlock&lt;/span&gt; display,bg,color %&amp;#125;&lt;/span&gt;&lt;span class=&#34;language-xml&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-xml&#34;&gt;content&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-xml&#34;&gt;&lt;/span&gt;&lt;span class=&#34;template-tag&#34;&gt;&amp;#123;% &lt;span class=&#34;name&#34;&gt;endhideBlock&lt;/span&gt; %&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;дҫӢеҰӮ 2:&lt;/p&gt;
&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% hideBlock жҲ‘жҳҜи°Ғ %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;зҲ·жҳҜ:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Weidows&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% endhideBlock %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;div class=&#34;hide-block&#34;&gt;&lt;button type=&#34;button&#34; class=&#34;hide-button&#34; style=&#34;&#34;&gt;жҲ‘жҳҜи°Ғ
    &lt;/button&gt;&lt;div class=&#34;hide-content&#34;&gt;&lt;p&gt;зҲ·жҳҜ:&lt;br&gt;
Weidows&lt;/p&gt;
&lt;/div&gt;&lt;/div&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;toggle-ж”¶зј©жЎҶ&#34;&gt;toggle(ж”¶зј©жЎҶ)&lt;/h3&gt;
&lt;figure class=&#34;highlight django&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;template-tag&#34;&gt;&amp;#123;% &lt;span class=&#34;name&#34;&gt;hideToggle&lt;/span&gt; display,bg,color %&amp;#125;&lt;/span&gt;&lt;span class=&#34;language-xml&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-xml&#34;&gt;content&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-xml&#34;&gt;&lt;/span&gt;&lt;span class=&#34;template-tag&#34;&gt;&amp;#123;% &lt;span class=&#34;name&#34;&gt;endhideToggle&lt;/span&gt; %&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;дҫӢеҰӮ 3:&lt;/p&gt;
&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% hideToggle жҲ‘жҳҜи°Ғ %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;зҲ·жҳҜ:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Weidows&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% endhideToggle %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;details class=&#34;toggle&#34; &gt;&lt;summary class=&#34;toggle-button&#34; style=&#34;&#34;&gt;жҲ‘жҳҜи°Ғ&lt;/summary&gt;&lt;div class=&#34;toggle-content&#34;&gt;&lt;p&gt;зҲ·жҳҜ:&lt;br&gt;
Weidows&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;tag-hide еҶ…зҡ„ж ҮзӯҫеӨ–жҢӮ content еҶ…йғҪдёҚе»әи®®жңү h1 - h6 зӯүж ҮйўҳгҖӮеӣ дёә Toc дјҡжҠҠйҡҗи—ҸеҶ…е®№ж Үйўҳд№ҹжҳҫзӨәеҮәжқҘпјҢиҖҢдё”еҪ“ж»ҡеҠЁеұҸе№•ж—¶пјҢеҰӮжһңйҡҗи—ҸеҶ…е®№жІЎжңүжҳҫзӨәеҮәжқҘпјҢдјҡеҜјиҮҙ Toc зҡ„ж»ҡеҠЁеҮәзҺ°ејӮеёёгҖӮ&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;mermaid&#34;&gt;mermaid&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;еҶҷжі•:&lt;/p&gt;
&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% mermaid %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;еҶ…е®№&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% endmermaid %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дҫӢеҰӮ:&lt;div class=&#34;mermaid-wrap&#34;&gt;&lt;pre class=&#34;mermaid-src&#34; hidden&gt;
  &amp;lt;div class&amp;#x3D;&amp;quot;mermaid-wrap&amp;quot;&amp;gt;&amp;lt;pre class&amp;#x3D;&amp;quot;mermaid-src&amp;quot; hidden&amp;gt;
  pie
  title Key elements in Product X
  &amp;quot;Calcium&amp;quot; : 42.96
  &amp;quot;Potassium&amp;quot; : 50.05
  &amp;quot;Magnesium&amp;quot; : 10.01
  &amp;quot;Iron&amp;quot; : 5
  &amp;lt;&amp;#x2F;pre&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;&amp;#x2F;p&amp;gt;
&amp;lt;&amp;#x2F;li&amp;gt;
&amp;lt;&amp;#x2F;ul&amp;gt;
  &lt;/pre&gt;&lt;/div&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;жҳҫзӨә:&lt;/p&gt;
&lt;div class=&#34;mermaid-wrap&#34;&gt;&lt;pre class=&#34;mermaid-src&#34; hidden&gt;
  pie
title Key elements in Product X
&amp;quot;Calcium&amp;quot; : 42.96
&amp;quot;Potassium&amp;quot; : 50.05
&amp;quot;Magnesium&amp;quot; : 10.01
&amp;quot;Iron&amp;quot; : 5
  &lt;/pre&gt;&lt;/div&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;е®ҳж–№еҺҹж–Ү:&lt;/p&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;mermaid ж ҮзұӨдёҚе…Ғи®ёеөҢеҘ—дәҺдёҖдәӣйҡҗи—ҸеұһжҖ§зҡ„ж ҮзұӨеӨ–жҢӮпјҢдҫӢеҰӮ: tag-hide еҶ…зҡ„ж ҮзұӨеӨ–жҢӮе’Ң tabs ж ҮзұӨеӨ–жҢӮпјҢиҝҷдјҡеҜјиҮҙ mermaid еӣҫзӨәж— жі•жӯЈеёёжҳҫзӨәпјҢдҪҝз”Ёж—¶иҜ·з•ҷж„ҸгҖӮ&lt;/li&gt;
&lt;li&gt;иҜ·дёҚиҰҒеҺӢзј© html д»Јз ҒпјҢдёҚз„¶дјҡеҜјиҮҙ mermaid жҳҫзӨәејӮеёё&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еҺӢзј© HTML еҫҲжңүеҝ…иҰҒ,еҰӮдҪ•жҺ’йҷӨиҝҷз§Қж·»еҠ дәҶ mermaid зҡ„ HTML ж–Үд»¶е‘ў?&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;жҲ‘з”Ёзҡ„еҰӮдёӢж–№ејҸ: жҠҠж·»еҠ дәҶ mermaid зҡ„ markdown ж–Үд»¶е‘ҪеҗҚдёә &lt;code&gt;xxx.mmd.md&lt;/code&gt;,иҝҷж · neat ж—¶е°ұдјҡиў«жҺ’йҷӨдәҶ.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;neat_html:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;exclude:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;**/*.mmd/*&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;tabs-ж Үзӯҫеқ—&#34;&gt;tabs(ж Үзӯҫеқ—)&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;еҶҷжі•:&lt;/p&gt;
&lt;figure class=&#34;highlight pgsql&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% tabs &lt;span class=&#34;keyword&#34;&gt;Unique&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;name&lt;/span&gt;, [&lt;span class=&#34;keyword&#34;&gt;index&lt;/span&gt;] %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!&lt;span class=&#34;comment&#34;&gt;-- tab [Tab caption] [@icon] --&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;markdownеҶ…е®№(&lt;span class=&#34;keyword&#34;&gt;inline&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!&lt;span class=&#34;comment&#34;&gt;-- endtab --&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% endtabs %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;Unique&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;name&lt;/span&gt;   : &lt;span class=&#34;keyword&#34;&gt;Unique&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;name&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;of&lt;/span&gt; tabs block tag &lt;span class=&#34;keyword&#34;&gt;without&lt;/span&gt; comma.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Will be used &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; #id&lt;span class=&#34;string&#34;&gt;&amp;#x27;s as prefix for each tab with their index numbers.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;                If there are whitespaces in name, for generate #id all whitespaces will replaced by dashes.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;                Only for current url of post/page must be unique!&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;[index]       : Index number of active tab.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;                If not specified, first tab (1) will be selected.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;                If index is -1, no tab will be selected. It&amp;#x27;&lt;/span&gt;s will be something &lt;span class=&#34;keyword&#34;&gt;like&lt;/span&gt; spoiler.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Optional parameter.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Tab caption] : Caption &lt;span class=&#34;keyword&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;current&lt;/span&gt; tab.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;If&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; caption specified, &lt;span class=&#34;keyword&#34;&gt;unique&lt;/span&gt; &lt;span class=&#34;type&#34;&gt;name&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; tab &lt;span class=&#34;keyword&#34;&gt;index&lt;/span&gt; suffix will be used &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; caption &lt;span class=&#34;keyword&#34;&gt;of&lt;/span&gt; tab.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;If&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; caption specified, but specified icon, caption will empty.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Optional parameter.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[@icon]       : FontAwesome icon &lt;span class=&#34;type&#34;&gt;name&lt;/span&gt; (&lt;span class=&#34;keyword&#34;&gt;full&lt;/span&gt;-&lt;span class=&#34;type&#34;&gt;name&lt;/span&gt;, look &lt;span class=&#34;keyword&#34;&gt;like&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;fas fa-font&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Can be specified &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;without&lt;/span&gt; space; e.g. &lt;span class=&#34;string&#34;&gt;&amp;#x27;Tab caption @icon&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;similar&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Tab caption@icon&amp;#x27;&lt;/span&gt;.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Optional parameter.&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дҫӢеҰӮ: (test2 ж Үзӯҫдёәйў„йҖүзҠ¶жҖҒ,жүҫдёҚеҲ°зҡ„иҜқе°ұжҳҜз¬¬дёҖдёӘ)&lt;/p&gt;
