ww.weibo.com/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;avatar:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;https://fastly.jsdelivr.net/gh/Weidows/Images/post/TLJBum386vcnI1P.png&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;descr:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;дёӯеңӢжңҖеӨ§зӨҫдәӨеҲҶдә«е№іеҸ°&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;name:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;Twitter&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;link:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;https://twitter.com/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;avatar:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;https://fastly.jsdelivr.net/gh/Weidows/Images/post/5VyHPQqR6LWF39a.png&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;descr:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;зӨҫдәӨеҲҶдә«е№іеҸ°&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;еҗ„з§ҚжҸ’д»¶&#34;&gt;еҗ„з§ҚжҸ’д»¶&lt;/h2&gt;
&lt;div class=&#34;tabs&#34; id=&#34;deployer&#34;&gt;&lt;ul class=&#34;nav-tabs&#34;&gt;&lt;li class=&#34;tab active&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-1&#34;&gt;deployer&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-2&#34;&gt;Live2D&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-3&#34;&gt;Steam-жёёжҲҸйЎөйқў&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-4&#34;&gt;bilibili-з•Әеү§&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-5&#34;&gt;Meting&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-6&#34;&gt;Gulp&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-7&#34;&gt;иұҶз“Ј(е·ІеҒңз”Ё)&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-8&#34;&gt;Random-йЎөйқў&lt;/button&gt;&lt;/li&gt;&lt;li class=&#34;tab&#34;&gt;&lt;button type=&#34;button&#34; data-href=&#34;#deployer-9&#34;&gt;neat-еҺӢзј©&lt;/button&gt;&lt;/li&gt;&lt;/ul&gt;&lt;div class=&#34;tab-contents&#34;&gt;&lt;div class=&#34;tab-item-content active&#34; id=&#34;deployer-1&#34;&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е®үиЈ…:&lt;/p&gt;
&lt;figure class=&#34;highlight ada&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install hexo-deployer-git &lt;span class=&#34;comment&#34;&gt;--save&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;е®ҳж–№й…ҚзҪ®ж–ҮжЎЈ(еҝ…иҰҒ)&lt;sup id=&#39;cite_ref-1&#39;&gt;&lt;a href=&#34;#cite_note-1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt;, дёӘдәәй…ҚзҪ®&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;deploy:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;repo:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;https://gitee.com/Weidows/Weidows.git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;branch:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;main&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;repo:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;https://github.com/Weidows/Weidows.github.io.git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;branch:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;main&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дҪҝз”Ё:&lt;/p&gt;
&lt;figure class=&#34;highlight ebnf&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;hexo deploy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;д№ҹеҸҜд»ҘеҸӮз…§дёӢйқўдёҖжқЎйҫҷжңҚеҠЎиҮӘиЎҢж·»еҠ еҝ«жҚ·ж–№ејҸ.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-2&#34;&gt;&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install --save hexo-helper-live2d&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;зҷҪзҢ« / й»‘зҢ«&lt;/p&gt;
  &lt;figure class=&#34;highlight gams&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install --save live2d-widget-&lt;span class=&#34;keyword&#34;&gt;model&lt;/span&gt;-tororo live2d-widget-&lt;span class=&#34;keyword&#34;&gt;model&lt;/span&gt;-hijiki&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;еҗҜз”ЁжЁЎеһӢ: еңЁ&lt;code&gt;/_config.yml&lt;/code&gt; йҮҢжүҫеҲ° model.use ж”№жҲҗжғіз”Ёзҡ„жЁЎеһӢж–Үд»¶еӨ№еҗҚ&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-3&#34;&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е®үиЈ…&lt;/p&gt;
&lt;figure class=&#34;highlight ada&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install hexo-steam-games &lt;span class=&#34;comment&#34;&gt;--save&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;й…ҚзҪ®&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;steam:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;steamId:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;xxx&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# steam64дҪҚId(йңҖиҰҒж”ҫеңЁеј•еҸ·йҮҢ),е°Ҷsteamеә“и®ҫзҪ®дёәе…¬ејҖ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;path:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;tags/games.html&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# йЎөйқўи·Ҝеҫ„пјҢй»ҳи®Өsteamgames/index.html&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;title:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;вӯҗпёҸе…»йёЎеңәвӯҗпёҸ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;quote:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Steamз»ҷзҲ·зҲ¬!еҲ«и®©жҲ‘е®¶EPICиҜҜдјҡ&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# еҶҷеңЁйЎөйқўејҖеӨҙзҡ„дёҖж®өиҜқ,ж”ҜжҢҒhtmlиҜӯжі•&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;tab:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;all&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# allжҲ–recent, all: жүҖжңүжёёжҲҸ, recent: жңҖиҝ‘жёёзҺ©зҡ„жёёжҲҸ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;length:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;imgUrl:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;https://pan.weidows.tech/d/local/img/avatar/avatar.png&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# еӣҫзүҮй“ҫжҺҘпјҢеңЁquoteдёӢйқўж”ҫдёҖеј еӣҫзүҮпјҢеӣҫзүҮй“ҫжҺҘеҲ°SteamдёӘдәәиө„ж–ҷпјҢеҸҜз•ҷз©ә&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;proxy:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# еҰӮжһңж— жі•и®ҝй—®steamзӨҫеҢәзҡ„иҜқиҜ·дҪҝз”Ёд»ЈзҗҶ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;host:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# д»ЈзҗҶipжҲ–еҹҹеҗҚ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;port:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# д»ЈзҗҶз«ҜеҸЈ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дҪҝз”Ё:&lt;/p&gt;
&lt;p&gt;&lt;code&gt;Hexo g&lt;/code&gt; д№ӢеүҚ &lt;code&gt;hexo steam -u&lt;/code&gt;, еҰӮжһңеӨұиҙҘйңҖиҰҒжүӢеҠЁ:&lt;/p&gt;
&lt;p&gt;жөҸи§ҲеҷЁжү“ејҖ&lt;code&gt;https://steamcommunity.com/profiles/76561198321099712/games/?tab=all&lt;/code&gt; {steamId}е’Ң{tab}еҲҶеҲ«жӣҝжҚўдёәдёҠйқўй…ҚзҪ®дёӯжҸҗеҲ°зҡ„ steamId е’Ң tab&lt;/p&gt;
&lt;p&gt;F12 жҺ§еҲ¶еҸ° console иҫ“е…ҘдёӢйқўеҶ…е®№жү§иЎҢ:&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;let&lt;/span&gt; script = &lt;span class=&#34;title function_&#34;&gt;jQuery&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;script[language=&amp;quot;javascript&amp;quot;]&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; games = [];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (&lt;span class=&#34;keyword&#34;&gt;let&lt;/span&gt; i = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; i &amp;lt; script.&lt;span class=&#34;property&#34;&gt;length&lt;/span&gt;; i++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (script.&lt;span class=&#34;title function_&#34;&gt;eq&lt;/span&gt;(i).&lt;span class=&#34;title function_&#34;&gt;html&lt;/span&gt;().&lt;span class=&#34;title function_&#34;&gt;includes&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;rgGames&amp;quot;&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;let&lt;/span&gt; rgGames = script.&lt;span class=&#34;title function_&#34;&gt;eq&lt;/span&gt;(i).&lt;span class=&#34;title function_&#34;&gt;html&lt;/span&gt;().&lt;span class=&#34;title function_&#34;&gt;match&lt;/span&gt;(&lt;span class=&#34;regexp&#34;&gt;/var.*?rgGames.*?=.*?(\[[\w\W]*?\&amp;#125;\&amp;#125;\]);/&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (rgGames) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      games = &lt;span class=&#34;title class_&#34;&gt;JSON&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;parse&lt;/span&gt;(rgGames[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;break&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable language_&#34;&gt;document&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;write&lt;/span&gt;(&lt;span class=&#34;title class_&#34;&gt;JSON&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;stringify&lt;/span&gt;(games))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;з”ҹжҲҗзҡ„еҶ…е®№еӨҚеҲ¶еҲ°&lt;code&gt;root/node_modules/hexo-steam-games/data/games.json&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;иҝҷдёӘдёҚз”Ё new йЎөйқў(дҪҶжҳҜж•°жҚ®ж–Үд»¶и·Ҝеҫ„ж— жі•ж”№)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-4&#34;&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е®үиЈ…:&lt;/p&gt;
&lt;figure class=&#34;highlight mipsasm&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm &lt;span class=&#34;keyword&#34;&gt;install &lt;/span&gt;hexo-&lt;span class=&#34;keyword&#34;&gt;bilibili-bangumi &lt;/span&gt;--save&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;й…ҚзҪ®: еҶҷе…Ҙ&lt;code&gt;root/_config.yml&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;bangumi:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;path:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;#йЎөйқўи·Ҝеҫ„&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;vmid:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## е“”е“©е“”е“©з•Әеү§йЎөйқўзҡ„ vmid(uid)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;title:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;иҝҪз•ӘеҲ—иЎЁ&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## йЎөйқўзҡ„ж Үйўҳ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;quote:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;з”ҹе‘ҪдёҚжҒҜпјҢиҝҪз•ӘдёҚжӯўпјҒ&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## еҶҷеңЁйЎөйқўејҖеӨҙзҡ„дёҖж®өиҜқпјҢж”ҜжҢҒ html иҜӯжі•&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;show:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## еҲқе§ӢжҳҫзӨәйЎөйқўпјҡ0: жғізңӢ , 1: еңЁзңӢ , 2: зңӢиҝҮпјҢй»ҳи®Өдёә 1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;loading:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## еӣҫзүҮеҠ иҪҪе®ҢжҲҗеүҚзҡ„ loading еӣҫзүҮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;metaColor:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;##  meta йғЁеҲҶ(з®Җд»ӢдёҠж–№)еӯ—дҪ“йўңиүІ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;color:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## з®Җд»Ӣеӯ—дҪ“йўңиүІ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;webp:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;progress:&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;## иҺ·еҸ–з•Әеү§ж•°жҚ®ж—¶жҳҜеҗҰжҳҫзӨәиҝӣеәҰжқЎпјҢй»ҳи®Өtrue&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еҸҜйҖүеҲӣе»әйЎөйқў,иҝӣе…Ҙ root/е‘Ҫд»ӨиЎҢ,жү§иЎҢ: &lt;code&gt;hexo new page bangumis&lt;/code&gt; ;еҪ“з„¶д№ҹеҸҜд»ҘзӣҙжҺҘеңЁ source/зӣҙжҺҘж–°е»әдёҖдёӘ markdown,з„¶еҗҺжҠҠж–Үд»¶еӨҙ type еҶҷдёә:&lt;code&gt;type: &amp;quot;bangumis&amp;quot;&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;http://xn--ihq6t34jk6j7t6abp2a90f.md&#34;&gt;е°қиҜ•иҝҮеҸҜд»ҘдёҚз”Ё.md&lt;/a&gt;,еңЁ_data йҮҢеҸӘж”ҫдёҠж•°жҚ®ж–Үд»¶ bangumis.json е°ұеҸҜд»ҘеңЁжҢҮе®ҡи·Ҝеҫ„з”ҹжҲҗдәҶ&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;жӣҙж–°/еҲ йҷӨж•°жҚ®:&lt;/p&gt;
&lt;figure class=&#34;highlight mipsasm&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;hexo &lt;span class=&#34;keyword&#34;&gt;bangumi &lt;/span&gt;-u&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;hexo &lt;span class=&#34;keyword&#34;&gt;bangumi &lt;/span&gt;-d&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-5&#34;&gt;&lt;blockquote&gt;
&lt;p&gt;еҗёеә• mini ж’ӯж”ҫеҷЁ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;йңҖиҰҒеҜје…Ҙ js е№¶йҖҡиҝҮеҜје…Ҙ css дҝ®ж”№ Aplayer зј©иҝӣж ·ејҸ:&lt;/p&gt;
&lt;p&gt;еңЁ_config.yml йҮҢдҝ®ж”№жңүдёҖе®ҡйҷҗеҲ¶,inject еҸӘиғҪжҗһи…ҡ source дёӯж–Үз« зҡ„е…¶дёӯжҹҗдёҖеұӮзӣ®еҪ•,еӨҡеұӮйңҖиҰҒдёҚеҗҢеұӮзә§зӣ®еҪ•еҗ„еј•з”ЁдёҖж¬Ў,еҰӮдёӢ:&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;inject:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;head:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;## - &amp;lt;link rel=&amp;quot;stylesheet&amp;quot; href=&amp;quot;./css/mine.css&amp;quot;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;bottom:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;## - &amp;lt;script src=&amp;quot;./js/mine.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;## - &amp;lt;script src=&amp;quot;../js/mine.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;## - &amp;lt;script src=&amp;quot;../../js/mine.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;## - &amp;lt;script src=&amp;quot;../../../js/mine_post.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;иҝҷйҮҢд»Ӣз»ҚеҸҰдёҖз§Қе…ЁеұҖ inject зҡ„ж–№жі•:&lt;/p&gt;
&lt;p&gt;жүҫеҲ° theme/xxx/layout/includes/layout.pug, еңЁжңҖеҗҺж·»еҠ еҰӮдёӢеӯ—ж®ө:&lt;/p&gt;
&lt;figure class=&#34;highlight routeros&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;script(&lt;span class=&#34;attribute&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;js/mine.js&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;link(&lt;span class=&#34;attribute&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;stylesheet&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;attribute&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;css/mine.css&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;жҢүз…§дёҠйқўеҸҜд»ҘиҮӘиЎҢдҝ®ж”№ JS/CSS зҡ„еј•е…Ҙ,е…ЁеұҖз”ҹж•Ҳ(жіЁж„ҸжңүеҸҜиғҪ PJAX дјҡдҪҝиҝҷз§Қеј•е…Ҙзҡ„ Js ж— ж•ҲеҢ–)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-6&#34;&gt;&lt;blockquote&gt;
&lt;p&gt;з”ЁдәҺеҺӢзј©ж–Үд»¶, еҸӮиҖғж–Үз«  &lt;sup id=&#39;cite_ref-2&#39;&gt;&lt;a href=&#34;#cite_note-2&#34;&gt;[2]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Cli е’ҢжЁЎеқ—&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install gulp -g&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;npm install gulp-htmlclean gulp-htmlmin gulp-imagemin gulp-minify-css gulp-uglify --save&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еңЁеҚҡе®ўж №зӣ®еҪ•ж–°е»ә&lt;code&gt;gulpfile.js&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; gulp = &lt;span class=&#34;built_in&#34;&gt;require&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;gulp&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; minifycss = &lt;span class=&#34;built_in&#34;&gt;require&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;gulp-minify-css&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; uglify = &lt;span class=&#34;built_in&#34;&gt;require&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;gulp-uglify&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; htmlmin = &lt;span class=&#34;built_in&#34;&gt;require&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;gulp-htmlmin&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; htmlclean = &lt;span class=&#34;built_in&#34;&gt;require&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;gulp-htmlclean&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; imagemin = &lt;span class=&#34;built_in&#34;&gt;require&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;gulp-imagemin&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// еҺӢзј©html&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gulp.&lt;span class=&#34;title function_&#34;&gt;task&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;minify-html&amp;quot;&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; gulp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;src&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public/**/*.html&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(&lt;span class=&#34;title function_&#34;&gt;htmlclean&lt;/span&gt;())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;title function_&#34;&gt;htmlmin&lt;/span&gt;(&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;removeComments&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;minifyJS&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;minifyCSS&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;minifyURLs&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(gulp.&lt;span class=&#34;title function_&#34;&gt;dest&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public&amp;quot;&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// еҺӢзј©css&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gulp.&lt;span class=&#34;title function_&#34;&gt;task&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;minify-css&amp;quot;&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; gulp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;src&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public/**/*.css&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;title function_&#34;&gt;minifycss&lt;/span&gt;(&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;compatibility&lt;/span&gt;: &lt;span class=&#34;string&#34;&gt;&amp;quot;ie8&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(gulp.&lt;span class=&#34;title function_&#34;&gt;dest&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public&amp;quot;&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// еҺӢзј©js&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gulp.&lt;span class=&#34;title function_&#34;&gt;task&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;minify-js&amp;quot;&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; gulp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;src&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public/js/**/*.js&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(&lt;span class=&#34;title function_&#34;&gt;uglify&lt;/span&gt;())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(gulp.&lt;span class=&#34;title function_&#34;&gt;dest&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public&amp;quot;&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// еҺӢзј©еӣҫзүҮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gulp.&lt;span class=&#34;title function_&#34;&gt;task&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;minify-images&amp;quot;&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; gulp&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;src&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public/images/**/*.*&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;title function_&#34;&gt;imagemin&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          imagemin.&lt;span class=&#34;title function_&#34;&gt;gifsicle&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;optimizationLevel&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; &amp;#125;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          imagemin.&lt;span class=&#34;title function_&#34;&gt;jpegtran&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;progressive&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt; &amp;#125;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          imagemin.&lt;span class=&#34;title function_&#34;&gt;optipng&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;optimizationLevel&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt; &amp;#125;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          imagemin.&lt;span class=&#34;title function_&#34;&gt;svgo&lt;/span&gt;(),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123; &lt;span class=&#34;attr&#34;&gt;verbose&lt;/span&gt;: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .&lt;span class=&#34;title function_&#34;&gt;pipe&lt;/span&gt;(gulp.&lt;span class=&#34;title function_&#34;&gt;dest&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;./public/images&amp;quot;&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// й»ҳи®Өд»»еҠЎ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gulp.&lt;span class=&#34;title function_&#34;&gt;task&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;default&amp;quot;&lt;/span&gt;, [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;minify-html&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;minify-css&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;minify-js&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;minify-images&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;]);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;з„¶еҗҺ&lt;code&gt;gulp&lt;/code&gt;е°ұеҸҜд»ҘеҺӢзј©дәҶ.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-7&#34;&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е®үиЈ…&lt;/p&gt;
&lt;figure class=&#34;highlight ada&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install hexo-douban &lt;span class=&#34;comment&#34;&gt;--save&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дҪҝз”Ё&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;douban:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;user:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;userID&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# дҪ зҡ„иұҶз“Ј ID.жү“ејҖиұҶз“ЈпјҢзҷ»е…ҘиҙҰжҲ·пјҢз„¶еҗҺеңЁеҸідёҠи§’зӮ№еҮ» &amp;quot;дёӘдәәдё»йЎө&amp;quot; пјҢиҝҷж—¶еҖҷең°еқҖж Ҹзҡ„ URL еӨ§жҰӮжҳҜиҝҷж ·пјҡ&amp;quot;https://www.douban.com/people/xxxxxx/&amp;quot; пјҢе…¶дёӯзҡ„&amp;quot;xxxxxx&amp;quot;е°ұжҳҜдҪ зҡ„дёӘдәә ID дәҶгҖӮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;builtin:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# жҳҜеҗҰе°Ҷз”ҹжҲҗйЎөйқўзҡ„еҠҹиғҪеөҢе…Ҙ hexo s е’Ң hexo g дёӯпјҢй»ҳи®ӨжҳҜ false,еҸҰдёҖеҸҜйҖүйЎ№дёә true(1.x.x зүҲжң¬ж–°еўһй…ҚзҪ®йЎ№)гҖӮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;timeout:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;10000&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# зҲ¬еҸ–ж•°жҚ®зҡ„и¶…ж—¶ж—¶й—ҙпјҢй»ҳи®ӨжҳҜ 10000ms ,еҰӮжһңеңЁдҪҝз”Ёж—¶еҸ‘зҺ°жҠҘдәҶи¶…ж—¶зҡ„й”ҷ(ETIMEOUT)еҸҜд»ҘжҠҠиҝҷдёӘж•°жҚ®и®ҫзҪ®зҡ„еӨ§дёҖзӮ№гҖӮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# еҰӮжһңеҸӘжғіжҳҫзӨәжҹҗдёҖдёӘйЎөйқў(жҜ”еҰӮ movie)пјҢйӮЈе°ұжҠҠе…¶д»–зҡ„й…ҚзҪ®йЎ№жіЁйҮҠжҺүеҚіеҸҜгҖӮ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;book:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;title:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;My book title&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# иҜҘйЎөйқўзҡ„ж Үйўҳ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;quote:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;My book quote&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# еҶҷеңЁйЎөйқўејҖеӨҙзҡ„дёҖж®өиҜқ,ж”ҜжҢҒ html иҜӯжі•.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;movie:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;title:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;My movie title&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;quote:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;My movie quote&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;game:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;title:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;My game title&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;quote:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;My game quote&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-8&#34;&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е®үиЈ…дҫқиө–е’ҢжҸ’д»¶&lt;/p&gt;
&lt;figure class=&#34;highlight autoit&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install object-&lt;span class=&#34;built_in&#34;&gt;assign&lt;/span&gt; hexo-generator-&lt;span class=&#34;built_in&#34;&gt;random&lt;/span&gt; --save&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еә”з”Ё&lt;/p&gt;
&lt;p&gt;жҸ’д»¶дјҡеңЁж №зӣ®еҪ•з”ҹжҲҗ &lt;code&gt;random.html&lt;/code&gt;.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;div class=&#34;tab-item-content&#34; id=&#34;deployer-9&#34;&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;е®үиЈ…&lt;/p&gt;
&lt;figure class=&#34;highlight ada&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install hexo-neat &lt;span class=&#34;comment&#34;&gt;--save&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;й…ҚзҪ®&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# еҚҡж–ҮеҺӢзј©&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;neat_enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;neat_html:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;exclude:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;neat_css:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;exclude:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;**/*.min.css&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;neat_js:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;mangle:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;output:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;compress:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;exclude:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;**/*.min.js&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;**/jquery.fancybox.pack.js&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;**/index.js&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;&lt;button type=&#34;button&#34; class=&#34;tab-to-top&#34; aria-label=&#34;scroll to top&#34;&gt;&lt;i class=&#34;fas fa-arrow-up&#34;&gt;&lt;/i&gt;&lt;/button&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;дёҖй”®дёүиҝһ&#34;&gt;дёҖй”®дёүиҝһ&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;жӯЈеёёзҡ„жөӢиҜ•жөҒзЁӢдёә&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;hexo clean&lt;/li&gt;
&lt;li&gt;hexo generate&lt;/li&gt;
&lt;li&gt;hexo server&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;жҜҸж¬Ўз”ҹжҲҗйңҖиҰҒзӯүдёҖж®өж—¶й—ҙ,жҖҺд№ҲжҠҠе®ғд»¬еҗҲжҲҗдёәдёҖжқЎжҢҮд»Өе‘ў?еҸӮдёӢ:&lt;/p&gt;
&lt;p&gt;е®ҡдҪҚеҚҡе®ўж №зӣ®еҪ•дёӢзҡ„&lt;code&gt;package.json&lt;/code&gt;, дҝ®ж”№&lt;code&gt;&amp;quot;scripts&amp;quot;&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight css&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;scripts&amp;quot;: &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;quot;&lt;span class=&#34;attribute&#34;&gt;all&lt;/span&gt;&amp;quot;: &lt;span class=&#34;string&#34;&gt;&amp;quot;hexo clean &amp;amp;&amp;amp; hexo generate &amp;amp;&amp;amp; hexo server&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;з„¶еҗҺе°ұеҸҜд»ҘдёҖй”®дҪҝз”ЁдәҶ.&lt;/p&gt;
&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GVty2h.png&#34; alt=&#34;20201205150401&#34; /&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;иҮӘе®ҡд№үжёІжҹ“жіЁе…Ҙ&#34;&gt;иҮӘе®ҡд№үжёІжҹ“жіЁе…Ҙ&lt;/h2&gt;
&lt;h3 id=&#34;дё»йўҳж–Үд»¶жіЁе…Ҙ&#34;&gt;дё»йўҳж–Үд»¶жіЁе…Ҙ&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;дёҖиҲ¬жҳҜеҶҷеңЁ&lt;code&gt;theme/xxx/source/&lt;/code&gt;йҮҢзҡ„&lt;code&gt;js/css&lt;/code&gt;йҮҢйқў&lt;/p&gt;
&lt;p&gt;йҡҸдҫҝиө·дёӘеҗҚеӯ—,жҜ”еҰӮжҲ‘зҡ„еҸ« mine.js е’Ң mine.css,йҮҢйқўеҶҷдёҠйңҖиҰҒзҡ„еҶ…е®№&lt;/p&gt;
&lt;p&gt;еңЁдё»йўҳй…ҚзҪ®ж–Үд»¶&lt;code&gt;_config.yml&lt;/code&gt;йҮҢжүҫеҲ°&lt;code&gt;inject:&lt;/code&gt;еӯ—ж®ө,дёҖиҲ¬ css еңЁ head,js еңЁ bottom йҮҢ,еҰӮдёӢ:&lt;/p&gt;
&lt;figure class=&#34;highlight routeros&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;inject:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  head:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;link &lt;span class=&#34;attribute&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;stylesheet&amp;quot;&lt;/span&gt; &lt;span class=&#34;attribute&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;./css/mine.css&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  bottom:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;script &lt;span class=&#34;attribute&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;./js/mine.js&amp;quot;&lt;/span&gt;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;дҪҶжҳҜеҠЎеҝ…жіЁж„Ҹиҝҷж ·еј•е…ҘеҸӘеҜ№&lt;code&gt;жҹҗдёҖеұӮ&lt;/code&gt;зӣ®еҪ•з”ҹж•Ҳ,жҜ”еҰӮдёҠйқўеҸӘеҜ№ public/з¬¬дёҖеұӮзӣ®еҪ•з”ҹж•Ҳ,е…¶дёӯеӯҗзӣ®еҪ•ж— ж•Ҳ,еҰӮжһңжғідҪҝе…¶з”ҹж•Ҳ:&lt;/p&gt;
&lt;figure class=&#34;highlight routeros&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;inject:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  head:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;link &lt;span class=&#34;attribute&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;stylesheet&amp;quot;&lt;/span&gt; &lt;span class=&#34;attribute&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;./css/mine.css&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;link &lt;span class=&#34;attribute&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;stylesheet&amp;quot;&lt;/span&gt; &lt;span class=&#34;attribute&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;../css/mine.css&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;link &lt;span class=&#34;attribute&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;stylesheet&amp;quot;&lt;/span&gt; &lt;span class=&#34;attribute&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;../../css/mine.css&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  bottom:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;script &lt;span class=&#34;attribute&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;./js/mine.js&amp;quot;&lt;/span&gt;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;script &lt;span class=&#34;attribute&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;../js/mine.js&amp;quot;&lt;/span&gt;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    - &amp;lt;script &lt;span class=&#34;attribute&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;../../js/mine.js&amp;quot;&lt;/span&gt;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;е–Ҹ,иҝҷж ·жҳҜи®©з¬¬дёҖдәҢдёүеұӮз”ҹж•ҲдәҶ,д»ҘжӯӨзұ»жҺЁ.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;дҝ®ж”№еҶ…йғЁж–Үд»¶жіЁе…Ҙ&#34;&gt;дҝ®ж”№еҶ…йғЁж–Үд»¶жіЁе…Ҙ&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;йҰ–е…Ҳж“ҚдҪңеҰӮдёҠйқўдёҖж ·ж–°е»әж–Үд»¶е№¶еҶҷеҘҪ js е’Ң css ж–Үд»¶,еҸӘжҳҜжіЁе…Ҙж–№ејҸдёҚеҗҢ&lt;/p&gt;
&lt;p&gt;жүҫеҲ°&lt;code&gt;theme/xxx/layout/include/layout.pug&lt;/code&gt;,еңЁеҶ…йғЁж·»еҠ еҰӮдёӢ:&lt;/p&gt;
&lt;figure class=&#34;highlight routeros&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;script(&lt;span class=&#34;attribute&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;js/mine.js&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;link(&lt;span class=&#34;attribute&#34;&gt;rel&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;stylesheet&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;attribute&#34;&gt;href&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;css/mine.css&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;иҝҷдёӨдёӘеҲҶеҲ«жҳҜеј•е…Ҙ js е’Ң css,еҸҜд»ҘеҲҶеҲ«еңЁ body е’Ң head йҮҢеҠ е…Ҙ,жіЁж„Ҹзј©иҝӣж јејҸ!&lt;/p&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;и§ЈйҮҠ:&lt;br&gt;
еңЁ Hexo generate ж—¶дјҡжҠҠ&lt;code&gt;theme/xxx/source/&lt;/code&gt;йҮҢдҪ еҶҷзҡ„ж–Үд»¶еӨҚеҲ¶еҲ°&lt;code&gt;public/&lt;/code&gt;еҜ№еә”зӣ®еҪ•йҮҢ&lt;/p&gt;
&lt;p&gt;дёҖиҲ¬ Hexo еңЁеј•з”Ёж—¶ж №зӣ®еҪ•жҳҜ&lt;code&gt;public/&lt;/code&gt;,жүҖд»ҘдёҠйқўжүҫзҡ„жҳҜ&lt;code&gt;public/js/mine.js&lt;/code&gt;е’Ң&lt;code&gt;public/css/mine.css&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;иҝҷж ·жіЁе…ҘеҸҜиғҪеӣ дёәжёІжҹ“дҪҚзҪ®е’Ңж—¶жңәдёҚеҜ№иҖҢжңӘз”ҹж•Ҳ,йңҖиҰҒй…Ңжғ…дҪҝз”Ё&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;еёёи§Ғй—®йўҳ&#34;&gt;еёёи§Ғй—®йўҳ&lt;/h2&gt;
&lt;h3 id=&#34;bangumis-steam-йЎөйқўеӣҫзүҮж— жі•еҠ иҪҪ&#34;&gt;bangumis-steam-йЎөйқўеӣҫзүҮж— жі•еҠ иҪҪ&lt;/h3&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/ZMAUSX.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;еҸҜиғҪжҳҜ lazyload-field и®ҫзҪ®дёә site дәҶ (е…ЁеұҖ), жҠҠе®ғж”№дёә post е°ұиЎҢдәҶ&lt;/p&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;lazyload:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;field:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;post&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# site/post&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h3 id=&#34;Pjax-жёІжҹ“еӨұж•Ҳи§ЈеҶіж–№жЎҲ&#34;&gt;Pjax-жёІжҹ“еӨұж•Ҳи§ЈеҶіж–№жЎҲ&lt;/h3&gt;
&lt;p&gt;з”ЁиҝҮзҡ„йғҪзҹҘйҒ“ Pjax еҸҜд»Ҙи®©зҪ‘йЎөеңЁйқһи·іиҪ¬зҡ„жғ…еҶөдёӢеұҖйғЁеҲ·ж–°жқҘдҪҝзҪ‘йЎөеҠ иҪҪйҖҹеәҰжҸҗеҚҮ&lt;/p&gt;
&lt;p&gt;дҪҶжҳҜдјҡеёҰжқҘйқһеёёеӨҡзҡ„ Bug,жҜ”еҰӮжҹҗдәӣдҫқиө– JS жёІжҹ“е’ҢеҠ иҪҪзҡ„жҸ’д»¶ж— ж•ҲеҢ–,жҲ–иҖ…зӣ‘еҗ¬е’ҢдәӨдә’дёҚеҘҸж•Ҳ&lt;/p&gt;
&lt;p&gt;зҪ‘дёҠжҗңзҡ„жңүдәӣжҳҜи®©еҗ„з§ҚжҸ’д»¶жң¬иә«еұҲжңҚ Pjax еҗ„з§Қдҝ®ж”№жёІжҹ“зӯ–з•Ҙ&lt;/p&gt;
&lt;p&gt;иҝҷйҮҢжҸҗеҮәдёҖдёӘиҷҪз„¶дёҚжҳҜж–°ж–№жі•дҪҶжҳҜд№ҹжҳҜдёӘдёҚй”ҷзҡ„и§ЈеҶіж–№жЎҲ:&lt;/p&gt;
&lt;hr&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;ж–Үд»¶е®ҡдҪҚ:&lt;/p&gt;
&lt;p&gt;иҝҷйҮҢдҝ®ж”№зҡ„жҳҜ Butterfly иҮӘеёҰзҡ„ Pjax з¬¬дёүж–№ pug,еҰӮжңүдёҚеҗҢйңҖиҰҒиҮӘиЎҢжҹҘжүҫ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;жүҫеҲ°&lt;code&gt;themes/butterfly/layout/includes/third-party/pjax.pug&lt;/code&gt;,жү“ејҖејҖе§Ӣдҝ®ж”№&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;е®ҡдҪҚ &lt;code&gt;document.addEventListener(&#39;pjax:complete&#39;, function ()&lt;/code&gt;иҝҷдёҖиЎҢ,иҝҷжҳҜзӣ‘еҗ¬ Pjax и·іиҪ¬йЎөйқўжҳҜеҗҰе®ҢжҲҗзҡ„еҮҪж•°,е№¶жү§иЎҢи·іиҪ¬е®ҢжҲҗеҗҺзҡ„жҢҮд»Ө&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еӨҚеҲ¶йңҖиҰҒйҮҚиҪҪзҡ„ JS,зІҳиҙҙеҲ°иҝҷдёӘеҮҪж•°жӢ¬еҸ·еҶ…йғЁ,е№¶ Hexo Server жөӢиҜ•дёҖдёӢ&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;еҺҹзҗҶе°ұжҳҜи®© Pjax еҠ иҪҪе®ҢжҲҗйЎөйқўеҗҺеҶҚи®© JS жёІжҹ“дёҖйҒҚ(дҪҶжҳҜеҸҜиғҪжңүдәӣеұҖйғЁжёІжҹ“иҝҳжҳҜж— жі•з”ҹж•Ҳ)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;valine-waline-иҜ„и®әж— жі•еҠ иҪҪ&#34;&gt;valine-waline-иҜ„и®әж— жі•еҠ иҪҪ&lt;/h3&gt;
&lt;p&gt;еӣ дёәжҹҗдәӣеҺҹеӣ , еӣҪйҷ…зүҲ LeanCloud дёҺ Vercel еҒңжӯўеӣҪеҶ…и®ҝй—®дәҶ, жҲ‘д»¬еҸҜд»ҘжҗһдёӘеӣҪеӨ–еҹҹеҗҚз»ҷ Vercel з»‘дёҠ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;е…ҚеӨҮжЎҲ, жңү free зҡ„жҜ”еҰӮ freedom&lt;/li&gt;
&lt;li&gt;Vercel жң¬иә«жҳҜеӣҪеӨ–жңҚеҠЎеҷЁ, еҸҜд»Ҙи°ғеҲ°еӣҪйҷ…зүҲ LeanCloud API&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;freedom иҮӘеёҰзҡ„еҹҹеҗҚз®ЎзҗҶдёҚеҘҪз”Ё, ж·»еҠ и®°еҪ•дјҡжҠҘй”ҷ (Error occured: Wild cards are not allowed!), жҺЁиҚҗиҪ¬еҲ° DNSPOD з®ЎзҗҶ&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://my.freenom.com/clientarea.php?action=domaindetails&#34;&gt;https://my.freenom.com/clientarea.php?action=domaindetails&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;manage domain -&amp;gt; management tools -&amp;gt; nameservers -&amp;gt; Use custom nameservers&lt;/p&gt;
&lt;p&gt;еЎ«дёҠдёӢйқў, з„¶еҗҺеңЁ &lt;a href=&#34;https://console.dnspod.cn/dns/weidows.tk/record&#34;&gt;DNSPOD&lt;/a&gt; ж·»еҠ еҜ№еә”еҹҹеҗҚе°ұиЎҢдәҶ &lt;sup id=&#39;cite_ref-3&#39;&gt;&lt;a href=&#34;#cite_note-3&#34;&gt;[3]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight stylus&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;elm&lt;span class=&#34;selector-class&#34;&gt;.dnspod&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.net&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mushroom&lt;span class=&#34;selector-class&#34;&gt;.dnspod&lt;/span&gt;.net&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;rss-зј–иҜ‘еҮәй”ҷ&#34;&gt;rss-зј–иҜ‘еҮәй”ҷ&lt;/h3&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/ZKIzYE.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;е‘Ҫд»ӨиЎҢзЁӢеәҸ/python-notebook зҡ„иҫ“еҮәжҲ–иҖ…зҪ‘дёҠеӨҚеҲ¶дёӢжқҘзҡ„дёңиҘҝжңүж—¶дјҡеёҰжңүеһӮзӣҙе®ҡдҪҚз¬ҰеҸ· &lt;sup id=&#39;cite_ref-4&#39;&gt;&lt;a href=&#34;#cite_note-4&#34;&gt;[4]&lt;/a&gt;&lt;/sup&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/ZKIpdv.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;еңЁ vscode дёӯдјҡеҮәзҺ°зәўжЎҶж ҮеҮәжқҘ, иҷҪз„¶еҚҡе®ўйЎөйқўеұ•зӨәжІЎй—®йўҳ, дҪҶжҳҜдјҡеҜјиҮҙ rss.xml ж–Үд»¶и§Јжһҗй”ҷиҜҜ, еҸҜд»ҘйҖҡиҝҮжҠҘй”ҷеүҚзҡ„дҝЎжҒҜе®ҡдҪҚеҲ°з¬ҰеҸ·жүҖеңЁдҪҚзҪ®&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;deploy-error-github-action&#34;&gt;deploy-error-github_action&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;fatal: could not read Username for вҖҳ&lt;a href=&#34;https://github.com&#34;&gt;https://github.com&lt;/a&gt;вҖҷ: No such device or address&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;й…ҚзҪ®ж јејҸзҡ„й—®йўҳ, еҸҜд»ҘеҸӮз…§жҲ‘зҡ„иҝҷдёӘй…ҚзҪ®&lt;/p&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;deploy:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;repo:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;github:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;url:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;https://github.com/Weidows/Weidows.github.io.git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;branch:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;main&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;token:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;xxxxxxxxxxx&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;# message: [message]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;name:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;Weidows&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;email:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;ceo@weidows.tech&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;еҲҶеүІзәҝ&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;еҖҹзү©иЎЁ&#34;&gt;еҖҹзү©иЎЁ&lt;/h2&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-1&#39; href=&#39;#cite_ref-1&#39;&gt;[1]&lt;/a&gt;: &lt;a href=&#34;https://github.com/hexojs/hexo-deployer-git&#34;&gt;https://github.com/hexojs/hexo-deployer-git&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-2&#39; href=&#39;#cite_ref-2&#39;&gt;[2]&lt;/a&gt;: &lt;a href=&#34;https://blog.csdn.net/fengdi_yuxi/article/details/94402350&#34;&gt;Hexo еҚҡе®ўд№ӢйҖҹеәҰдјҳеҢ–&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-3&#39; href=&#39;#cite_ref-3&#39;&gt;[3]&lt;/a&gt;: &lt;a href=&#34;https://blog.csdn.net/weixin_34163313/article/details/112220858&#34;&gt;cname и§Јжһҗж•ҷзЁӢ_3 еҲҶй’ҹпјҢе…Қиҙ№жӢҘжңүдҪ зҡ„дё“еұһеҹҹеҗҚвҖ”вҖ”е…Қиҙ№дёҖзә§еҹҹеҗҚжіЁеҶҢз”іиҜ·еҸҠеҹҹеҗҚи§Јжһҗж•ҷзЁӢвҖҰ&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a name=&#39;cite_note-4&#39; href=&#39;#cite_ref-4&#39;&gt;[4]&lt;/a&gt;: &lt;a href=&#34;https://blog.51cto.com/laoshifu/4839614&#34;&gt;ASCII жҺ§еҲ¶еӯ—з¬Ұ_mb618d1c8a55b34 зҡ„жҠҖжңҜеҚҡе®ў_51CTO еҚҡе®ў&lt;/a&gt;&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;
